fileprivate struct FfiConverterTimestamp: FfiConverterRustBuffer {
    typealias SwiftType = Date

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Date {
        let seconds: Int64 = try readInt(&buf)
        let nanoseconds: UInt32 = try readInt(&buf)
        if seconds >= 0 {
            let delta = Double(seconds) + (Double(nanoseconds) / 1.0e9)
            return Date.init(timeIntervalSince1970: delta)
        } else {
            let delta = Double(seconds) - (Double(nanoseconds) / 1.0e9)
            return Date.init(timeIntervalSince1970: delta)
        }
    }

    public static func write(_ value: Date, into buf: inout [UInt8]) {
        var delta = value.timeIntervalSince1970
        var sign: Int64 = 1
        if delta < 0 {
            // The nanoseconds portion of the epoch offset must always be
            // positive, to simplify the calculation we will use the absolute
            // value of the offset.
            sign = -1
            delta = -delta
        }
        if delta.rounded(.down) > Double(Int64.max) {
            fatalError("Timestamp overflow, exceeds max bounds supported by Uniffi")
        }
        let seconds = Int64(delta)
        let nanoseconds = UInt32((delta - Double(seconds)) * 1.0e9)
        writeInt(&buf, sign * seconds)
        writeInt(&buf, nanoseconds)
    }
}


public struct Room {
    public var roomId: String
    public var passcode: String
    public var publickeyFingerprint: String
    public var peerIp: String
    public var peerPort: UInt16
    public var fileName: String
    public var fileHash: String
    public var sent: UInt32
    public var total: UInt32
    public var createdAt: Date

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(roomId: String, passcode: String, publickeyFingerprint: String, peerIp: String, peerPort: UInt16, fileName: String, fileHash: String, sent: UInt32, total: UInt32, createdAt: Date) {
        self.roomId = roomId
        self.passcode = passcode
        self.publickeyFingerprint = publickeyFingerprint
        self.peerIp = peerIp
        self.peerPort = peerPort
        self.fileName = fileName
        self.fileHash = fileHash
        self.sent = sent
        self.total = total
        self.createdAt = createdAt
    }
}


extension Room: Equatable, Hashable {
    public static func ==(lhs: Room, rhs: Room) -> Bool {
        if lhs.roomId != rhs.roomId {
            return false
        }
        if lhs.passcode != rhs.passcode {
            return false
        }
        if lhs.publickeyFingerprint != rhs.publickeyFingerprint {
            return false
        }
        if lhs.peerIp != rhs.peerIp {
            return false
        }
        if lhs.peerPort != rhs.peerPort {
            return false
        }
        if lhs.fileName != rhs.fileName {
            return false
        }
        if lhs.fileHash != rhs.fileHash {
            return false
        }
        if lhs.sent != rhs.sent {
            return false
        }
        if lhs.total != rhs.total {
            return false
        }
        if lhs.createdAt != rhs.createdAt {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(roomId)
        hasher.combine(passcode)
        hasher.combine(publickeyFingerprint)
        hasher.combine(peerIp)
        hasher.combine(peerPort)
        hasher.combine(fileName)
        hasher.combine(fileHash)
        hasher.combine(sent)
        hasher.combine(total)
        hasher.combine(createdAt)
    }
}


